use crate::outbox::Outbox;
use crate::ring::{channel, Consumer, Producer, RingError};
use crate::sequencer::run_core;
use crate::telemetry::{now_mono_ns, Telemetry, TelemetryConfig};
use crate::wire::{
    self, decode_hello, encode_goaway, encode_hello_ack, encode_transport_frame, FrameKind,
    HelloAck, TransportFrame, SCHEMA_VERSION,
};
use std::io::{self, ErrorKind, Read, Write};
use std::net::{Shutdown, TcpListener, TcpStream};
use std::path::{Path, PathBuf};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::Arc;
use std::thread;
use std::time::{Duration, Instant};

const SERVER_MAX_FRAME_LENGTH: u32 = 1_048_576;
const DEFAULT_HEARTBEAT_MS: u32 = 1000;
const RING_CAPACITY: usize = 1024;

#[derive(Clone)]
pub struct RuntimeConfig {
    pub run_dir: PathBuf,
    pub ordp_endpoint: String,
    pub outbox_path: PathBuf,
    pub telemetry_enabled: bool,
}

pub fn run_from_env() -> io::Result<()> {
    let mut run_dir = None;
    let mut telemetry = std::env::var("SPINE_TELEMETRY").is_ok_and(|v| v == "1");
    for arg in std::env::args().skip(1) {
        if arg == "--telemetry" {
            telemetry = true;
        } else if run_dir.is_none() {
            run_dir = Some(PathBuf::from(arg));
        }
    }
    let run_dir = run_dir
        .or_else(|| std::env::var_os("SPINE_RUN_DIR").map(PathBuf::from))
        .ok_or_else(|| io::Error::new(ErrorKind::InvalidInput, "missing run dir"))?;
    let config = load_runtime_config(&run_dir, telemetry)?;
    run(config)
}

pub fn load_runtime_config(run_dir: &Path, telemetry_enabled: bool) -> io::Result<RuntimeConfig> {
    let ordp_endpoint = std::env::var("SPINE_ORDP_ENDPOINT").map_err(|_| {
        io::Error::new(
            ErrorKind::InvalidInput,
            "missing SPINE_ORDP_ENDPOINT environment variable",
        )
    })?;
    let outbox_path = std::env::var("SPINE_OBOX_PATH").map_err(|_| {
        io::Error::new(
            ErrorKind::InvalidInput,
            "missing SPINE_OBOX_PATH environment variable",
        )
    })?;
    Ok(RuntimeConfig {
        run_dir: run_dir.to_path_buf(),
        ordp_endpoint,
        outbox_path: PathBuf::from(outbox_path),
        telemetry_enabled,
    })
}

pub fn run(config: RuntimeConfig) -> io::Result<()> {
    std::fs::create_dir_all(&config.run_dir)?;
    let listener = TcpListener::bind(&config.ordp_endpoint)?;

    let outbox = Outbox::create(&config.outbox_path)?;
    publish_descriptor(&config)?;

    let (mut stream, _) = listener.accept()?;
    let negotiated = handshake(&mut stream)?;

    let (ingress_producer, ingress_consumer) = channel(RING_CAPACITY);
    let (ack_producer, ack_consumer) = channel(RING_CAPACITY);
    let input_drained = Arc::new(AtomicBool::new(false));
    let writer_done = Arc::new(AtomicBool::new(false));

    let reader_stream = stream.try_clone()?;
    let writer_stream = stream;

    let reader = {
        let input_drained = Arc::clone(&input_drained);
        thread::spawn(move || {
            reader_loop(
                reader_stream,
                ingress_producer,
                input_drained,
                negotiated.max_frame_length,
            )
        })
    };
    let core = {
        let input_drained = Arc::clone(&input_drained);
        let writer_done = Arc::clone(&writer_done);
        let telemetry = Telemetry::new(TelemetryConfig {
            enabled: config.telemetry_enabled,
            metrics_path: config.run_dir.join("metrics.json"),
            latency_path: config.run_dir.join("publish-ts.bin"),
        });
        thread::spawn(move || {
            run_core(
                ingress_consumer,
                ack_producer,
                input_drained,
                writer_done,
                outbox,
                telemetry,
            )
        })
    };
    let writer = {
        let writer_done = Arc::clone(&writer_done);
        thread::spawn(move || {
            writer_loop(
                writer_stream,
                ack_consumer,
                writer_done,
                negotiated.heartbeat_interval_ms,
            )
        })
    };

    join_io(reader, "reader")?;
    join_io(core, "core")?;
    join_io(writer, "writer")?;
    Ok(())
}

#[derive(Clone, Copy)]
struct Negotiated {
    max_frame_length: u32,
    heartbeat_interval_ms: u32,
}

fn handshake(stream: &mut TcpStream) -> io::Result<Negotiated> {
    let frame = read_frame(stream, SERVER_MAX_FRAME_LENGTH)?;
    if frame.kind != FrameKind::Hello {
        reject_handshake(stream)?;
        return Err(io::Error::new(ErrorKind::InvalidData, "expected HELLO"));
    }
    let hello = match decode_hello(&frame.payload) {
        Ok(v) => v,
        Err(_) => {
            reject_handshake(stream)?;
            return Err(io::Error::new(ErrorKind::InvalidData, "bad HELLO"));
        }
    };
    if hello.min_schema_version > SCHEMA_VERSION || hello.max_schema_version < SCHEMA_VERSION {
        reject_handshake(stream)?;
        return Err(io::Error::new(ErrorKind::InvalidData, "unsupported schema"));
    }
    let negotiated = Negotiated {
        max_frame_length: hello.max_frame_length.min(SERVER_MAX_FRAME_LENGTH),
        heartbeat_interval_ms: if hello.heartbeat_interval_ms == 0 {
            DEFAULT_HEARTBEAT_MS
        } else {
            hello.heartbeat_interval_ms
        },
    };
    let mut payload = Vec::new();
    encode_hello_ack(
        HelloAck {
            schema_version: SCHEMA_VERSION,
            max_frame_length: negotiated.max_frame_length,
            heartbeat_interval_ms: negotiated.heartbeat_interval_ms,
            result: 0,
        },
        &mut payload,
    );
    let mut frame = Vec::new();
    encode_transport_frame(FrameKind::HelloAck, &payload, &mut frame);
    stream.write_all(&frame)?;
    stream.flush()?;
    Ok(negotiated)
}

fn reject_handshake(stream: &mut TcpStream) -> io::Result<()> {
    let mut payload = Vec::new();
    encode_hello_ack(
        HelloAck {
            schema_version: 0,
            max_frame_length: SERVER_MAX_FRAME_LENGTH,
            heartbeat_interval_ms: DEFAULT_HEARTBEAT_MS,
            result: 1,
        },
        &mut payload,
    );
    let mut frame = Vec::new();
    encode_transport_frame(FrameKind::HelloAck, &payload, &mut frame);
    let mut goaway = Vec::new();
    let mut goaway_payload = Vec::new();
    encode_goaway(1, &mut goaway_payload);
    encode_transport_frame(FrameKind::Goaway, &goaway_payload, &mut goaway);
    stream.write_all(&frame)?;
    stream.write_all(&goaway)?;
    stream.flush()
}

fn reader_loop(
    mut stream: TcpStream,
    ingress: Producer,
    input_drained: Arc<AtomicBool>,
    max_frame_length: u32,
) -> io::Result<()> {
    loop {
        let frame = match read_frame_eof(&mut stream, max_frame_length)? {
            Some(frame) => frame,
            None => {
                input_drained.store(true, Ordering::Release);
                return Ok(());
            }
        };
        match frame.kind {
            FrameKind::Record => {
                let ingress_ns = now_mono_ns();
                match ingress.push(&frame.payload, ingress_ns) {
                    Ok(()) => {}
                    Err(RingError::TooLarge { .. }) => {
                        input_drained.store(true, Ordering::Release);
                        return Err(io::Error::new(
                            ErrorKind::InvalidData,
                            "record exceeds slot",
                        ));
                    }
                    Err(err) => {
                        input_drained.store(true, Ordering::Release);
                        return Err(io::Error::other(format!("{err:?}")));
                    }
                }
            }
            FrameKind::Heartbeat => {}
            _ => {
                return Err(io::Error::new(
                    ErrorKind::InvalidData,
                    "unexpected client frame",
                ))
            }
        }
    }
}

fn writer_loop(
    mut stream: TcpStream,
    ack_ring: Consumer,
    writer_done: Arc<AtomicBool>,
    heartbeat_interval_ms: u32,
) -> io::Result<()> {
    let heartbeat_interval = Duration::from_millis(u64::from(heartbeat_interval_ms.max(1)));
    let mut next_heartbeat = Instant::now() + heartbeat_interval;
    loop {
        match ack_ring.try_pop() {
            Ok(item) => {
                let mut frame = Vec::new();
                encode_transport_frame(FrameKind::Record, &item.bytes, &mut frame);
                stream.write_all(&frame)?;
                stream.flush()?;
            }
            Err(RingError::Empty) if writer_done.load(Ordering::Acquire) => break,
            Err(RingError::Empty) => {
                if Instant::now() >= next_heartbeat {
                    let mut frame = Vec::new();
                    encode_transport_frame(FrameKind::Heartbeat, &[], &mut frame);
                    stream.write_all(&frame)?;
                    stream.flush()?;
                    next_heartbeat = Instant::now() + heartbeat_interval;
                } else {
                    thread::sleep(Duration::from_micros(50));
                }
            }
            Err(err) => return Err(io::Error::other(format!("{err:?}"))),
        }
    }
    stream.flush()?;
    stream.shutdown(Shutdown::Write)
}

fn read_frame(stream: &mut TcpStream, max_frame_length: u32) -> io::Result<TransportFrame> {
    read_frame_eof(stream, max_frame_length)?
        .ok_or_else(|| io::Error::new(ErrorKind::UnexpectedEof, "connection closed"))
}

fn read_frame_eof(
    stream: &mut TcpStream,
    max_frame_length: u32,
) -> io::Result<Option<TransportFrame>> {
    let mut len = [0u8; 4];
    let mut read = 0usize;
    while read < len.len() {
        match stream.read(&mut len[read..])? {
            0 if read == 0 => return Ok(None),
            0 => {
                return Err(io::Error::new(
                    ErrorKind::UnexpectedEof,
                    "partial frame length",
                ))
            }
            n => read += n,
        }
    }
    let frame_length = u32::from_le_bytes(len);
    if frame_length == 0 || frame_length > max_frame_length {
        return Err(io::Error::new(ErrorKind::InvalidData, "bad frame length"));
    }
    let mut payload = vec![0u8; frame_length as usize];
    stream.read_exact(&mut payload)?;
    let kind = wire::FrameKind::from_byte(payload[0])
        .map_err(|_| io::Error::new(ErrorKind::InvalidData, "bad frame kind"))?;
    Ok(Some(TransportFrame {
        kind,
        payload: payload[1..].to_vec(),
    }))
}

fn publish_descriptor(config: &RuntimeConfig) -> io::Result<()> {
    let metrics = config.run_dir.join("metrics.json");
    let latency = config.run_dir.join("publish-ts.bin");
    let telemetry = if config.telemetry_enabled {
        format!(
            "{{\"metrics_dump\":\"{}\",\"publish_timestamps\":\"{}\"}}",
            escape_json(&metrics.to_string_lossy()),
            escape_json(&latency.to_string_lossy())
        )
    } else {
        "null".to_string()
    };
    // `drain` is a snake_case object {mode, handle} per boundary-adapter.md obligation 1
    // (handle is null for half_close). The benchmarker reads only the telemetry pointers.
    let descriptor = format!(
        "{{\"ordp_endpoint\":\"{}\",\"outbox_dir\":\"{}\",\"outbox_glob\":\"*.obox\",\"drain\":{{\"mode\":\"half_close\",\"handle\":null}},\"sanctioned_divergence\":false,\"state_probe\":null,\"telemetry\":{}}}\n",
        escape_json(&config.ordp_endpoint),
        escape_json(&config.run_dir.to_string_lossy()),
        telemetry
    );
    let tmp = config
        .run_dir
        .join(format!(".descriptor.{}.tmp", crate::telemetry::now_ns()));
    std::fs::write(&tmp, descriptor)?;
    std::fs::rename(tmp, config.run_dir.join("descriptor.json"))
}

fn escape_json(s: &str) -> String {
    s.replace('\\', "\\\\").replace('"', "\\\"")
}

fn join_io(handle: thread::JoinHandle<io::Result<()>>, name: &'static str) -> io::Result<()> {
    match handle.join() {
        Ok(result) => result,
        Err(_) => Err(io::Error::other(format!("{name} thread panicked"))),
    }
}

