use crate::wire;
use std::fs::File;
use std::io::{BufWriter, Write};
use std::path::Path;

pub struct Outbox {
    writer: BufWriter<File>,
    next_frame_seq: u64,
}

impl Outbox {
    pub fn create(path: &Path) -> std::io::Result<Self> {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let file = File::create(path)?;
        let mut writer = BufWriter::new(file);
        writer.write_all(&wire::write_obox_header(1))?;
        Ok(Self {
            writer,
            next_frame_seq: 1,
        })
    }

    pub fn append_response_frame(&mut self, record_bytes: &[u8]) -> std::io::Result<()> {
        let mut frame = Vec::new();
        wire::encode_log_frame(self.next_frame_seq, record_bytes, &mut frame);
        self.write_frame(frame)
    }

    pub fn append_response_record(
        &mut self,
        record: &wire::records::Record,
    ) -> std::io::Result<()> {
        let mut frame = Vec::new();
        wire::encode_log_frame_record(
            self.next_frame_seq,
            |frame| wire::records::encode_record(record, frame),
            &mut frame,
        );
        self.write_frame(frame)
    }

    fn write_frame(&mut self, frame: Vec<u8>) -> std::io::Result<()> {
        self.next_frame_seq = self
            .next_frame_seq
            .checked_add(1)
            .expect("outbox frame sequence overflow");
        self.writer.write_all(&frame)
    }

    pub fn flush(&mut self) -> std::io::Result<()> {
        self.writer.flush()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::wire::records::{encode_record, ClockTickRequest, Record};
    use std::io::Read;

    #[test]
    fn header_is_written_and_validates() {
        let path = std::env::temp_dir().join(format!(
            "spine-obox-test-{}-{}.obox",
            std::process::id(),
            crate::telemetry::now_ns()
        ));
        {
            let mut outbox = Outbox::create(&path).unwrap();
            outbox.flush().unwrap();
        }
        let mut bytes = Vec::new();
        File::open(&path).unwrap().read_to_end(&mut bytes).unwrap();
        assert_eq!(bytes.len(), 64);
        assert_eq!(wire::validate_obox_header(&bytes).unwrap(), 1);
        let _ = std::fs::remove_file(path);
    }

    #[test]
    fn append_response_frame_assigns_contiguous_frame_sequence() {
        let path = std::env::temp_dir().join(format!(
            "spine-obox-seq-test-{}-{}.obox",
            std::process::id(),
            crate::telemetry::now_ns()
        ));
        let mut record = Vec::new();
        encode_record(
            &Record::ClockTickRequest(ClockTickRequest { now: 123 }),
            &mut record,
        );
        {
            let mut outbox = Outbox::create(&path).unwrap();
            outbox.append_response_frame(&record).unwrap();
            outbox.append_response_frame(&record).unwrap();
            outbox.flush().unwrap();
        }
        let mut bytes = Vec::new();
        File::open(&path).unwrap().read_to_end(&mut bytes).unwrap();
        assert_eq!(wire::validate_obox_header(&bytes[..64]).unwrap(), 1);
        let first_len = u32::from_le_bytes(bytes[64..68].try_into().unwrap()) as usize;
        let first_end = 68 + first_len;
        assert_eq!(
            wire::validate_log_frame(&bytes[64..first_end]).unwrap().0,
            1
        );
        assert_eq!(wire::validate_log_frame(&bytes[first_end..]).unwrap().0, 2);
        let _ = std::fs::remove_file(path);
    }
}

