use std::cell::{Cell, UnsafeCell};
use std::marker::PhantomData;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::thread;

pub const SLOT_CAP: usize = 4096;

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum RingError {
    Full,
    Empty,
    TooLarge { len: usize, cap: usize },
}

#[derive(Debug, Clone)]
pub struct RingItem {
    pub bytes: Vec<u8>,
    pub ingress_ns: u64,
}

struct Slot {
    len: usize,
    ingress_ns: u64,
    bytes: [u8; SLOT_CAP],
}

impl Slot {
    fn empty() -> Self {
        Self {
            len: 0,
            ingress_ns: 0,
            bytes: [0; SLOT_CAP],
        }
    }
}

struct Inner {
    slots: Box<[UnsafeCell<Slot>]>,
    mask: usize,
    head: AtomicUsize,
    tail: AtomicUsize,
}

unsafe impl Send for Inner {}
unsafe impl Sync for Inner {}

pub struct Producer {
    inner: Arc<Inner>,
    _not_sync: PhantomData<Cell<()>>,
}

pub struct Consumer {
    inner: Arc<Inner>,
    _not_sync: PhantomData<Cell<()>>,
}

pub fn channel(capacity: usize) -> (Producer, Consumer) {
    assert!(capacity.is_power_of_two());
    assert!(capacity > 0);
    let slots = (0..capacity)
        .map(|_| UnsafeCell::new(Slot::empty()))
        .collect::<Vec<_>>()
        .into_boxed_slice();
    let inner = Arc::new(Inner {
        slots,
        mask: capacity - 1,
        head: AtomicUsize::new(0),
        tail: AtomicUsize::new(0),
    });
    (
        Producer {
            inner: Arc::clone(&inner),
            _not_sync: PhantomData,
        },
        Consumer {
            inner,
            _not_sync: PhantomData,
        },
    )
}

impl Producer {
    pub fn try_push(&self, bytes: &[u8], ingress_ns: u64) -> Result<(), RingError> {
        if bytes.len() > SLOT_CAP {
            return Err(RingError::TooLarge {
                len: bytes.len(),
                cap: SLOT_CAP,
            });
        }
        let tail = self.inner.tail.load(Ordering::Relaxed);
        let head = self.inner.head.load(Ordering::Acquire);
        if tail.wrapping_sub(head) == self.capacity() {
            return Err(RingError::Full);
        }
        let idx = tail & self.inner.mask;
        // The endpoint split guarantees this is the only producer mutating this slot.
        let slot = unsafe { &mut *self.inner.slots[idx].get() };
        slot.len = bytes.len();
        slot.ingress_ns = ingress_ns;
        slot.bytes[..bytes.len()].copy_from_slice(bytes);
        self.inner
            .tail
            .store(tail.wrapping_add(1), Ordering::Release);
        Ok(())
    }

    pub fn push(&self, bytes: &[u8], ingress_ns: u64) -> Result<(), RingError> {
        loop {
            match self.try_push(bytes, ingress_ns) {
                Err(RingError::Full) => thread::yield_now(),
                other => return other,
            }
        }
    }

    fn capacity(&self) -> usize {
        self.inner.slots.len()
    }
}

impl Consumer {
    pub fn is_empty(&self) -> bool {
        self.inner.head.load(Ordering::Acquire) == self.inner.tail.load(Ordering::Acquire)
    }

    pub fn try_pop(&self) -> Result<RingItem, RingError> {
        let head = self.inner.head.load(Ordering::Relaxed);
        let tail = self.inner.tail.load(Ordering::Acquire);
        if head == tail {
            return Err(RingError::Empty);
        }
        let idx = head & self.inner.mask;
        // The endpoint split guarantees this is the only consumer reading this slot.
        let slot = unsafe { &*self.inner.slots[idx].get() };
        let out = RingItem {
            bytes: slot.bytes[..slot.len].to_vec(),
            ingress_ns: slot.ingress_ns,
        };
        self.inner
            .head
            .store(head.wrapping_add(1), Ordering::Release);
        Ok(out)
    }

    pub fn pop(&self) -> RingItem {
        loop {
            if let Ok(item) = self.try_pop() {
                return item;
            }
            thread::yield_now();
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn full_empty_and_fifo_are_preserved() {
        let (producer, consumer) = channel(2);
        assert_eq!(consumer.try_pop().unwrap_err(), RingError::Empty);
        producer.try_push(b"one", 1).unwrap();
        producer.try_push(b"two", 2).unwrap();
        assert_eq!(producer.try_push(b"three", 3).unwrap_err(), RingError::Full);
        assert_eq!(consumer.try_pop().unwrap().bytes, b"one");
        assert_eq!(consumer.try_pop().unwrap().bytes, b"two");
        assert_eq!(consumer.try_pop().unwrap_err(), RingError::Empty);
    }

    #[test]
    fn wrap_around_keeps_order() {
        let (producer, consumer) = channel(4);
        for i in 0u8..4 {
            producer.try_push(&[i], u64::from(i)).unwrap();
        }
        for i in 0u8..2 {
            assert_eq!(consumer.try_pop().unwrap().bytes, vec![i]);
        }
        producer.try_push(&[4], 4).unwrap();
        producer.try_push(&[5], 5).unwrap();
        for i in 2u8..6 {
            assert_eq!(consumer.try_pop().unwrap().bytes, vec![i]);
        }
    }

    #[test]
    fn two_threads_transfer_in_order() {
        let (producer, consumer) = channel(8);
        let handle = std::thread::spawn(move || {
            for i in 0u16..1000 {
                producer.push(&i.to_le_bytes(), u64::from(i)).unwrap();
            }
        });
        for i in 0u16..1000 {
            let item = consumer.pop();
            assert_eq!(item.bytes, i.to_le_bytes());
            assert_eq!(item.ingress_ns, u64::from(i));
        }
        handle.join().unwrap();
    }
}

