impl Default for Sequencer {
    fn default() -> Self {
        Self::new()
    }
}

pub fn run_core(
    ingress: Consumer,
    ack_ring: Producer,
    input_drained: Arc<AtomicBool>,
    writer_done: Arc<AtomicBool>,
    mut outbox: Outbox,
    mut telemetry: Telemetry,
) -> std::io::Result<()> {
    let mut sequencer = Sequencer::new();
    loop {
        match ingress.try_pop() {
            Ok(item) => {
                let ack = sequencer.accept_with_sink(&item.bytes, &mut outbox)?;
                if ack.disposition == AckKind::Sequenced {
                    telemetry.record_seq(ack.seq, item.ingress_ns, now_mono_ns());
                }
                let ack_bytes = encode_ack_record(&ack);
                ack_ring
                    .push(&ack_bytes, 0)
                    .map_err(|err| std::io::Error::other(format!("{err:?}")))?;
            }
            Err(RingError::Empty) if input_drained.load(Ordering::Acquire) => break,
            Err(RingError::Empty) => thread::sleep(Duration::from_micros(50)),
            Err(err) => {
                return Err(std::io::Error::other(format!(
                    "ingress ring pop failed: {err:?}"
                )));
            }
        }
    }
    outbox.flush()?;
    telemetry.dump()?;
    writer_done.store(true, Ordering::Release);
    Ok(())
}

pub fn encode_ack_record(ack: &Ack) -> Vec<u8> {
    let mut out = Vec::new();
    records::encode_record(&Record::Ack(ack.clone()), &mut out);
    out
}

fn sequenced_ack(idem: Idem, seq: u64) -> Ack {
    Ack {
        idem,
        seq,
        disposition: AckKind::Sequenced,
        shed_reason: None,
    }
}

fn shed_malformed_ack(idem: Idem) -> Ack {
    Ack {
        idem,
        seq: 0,
        disposition: AckKind::Shed,
        shed_reason: Some(ShedReason::Malformed),
    }
}

pub trait ResponseSink {
    fn append_response_frame(&mut self, record_bytes: &[u8]) -> std::io::Result<()>;

    fn append_response_record(&mut self, record: &Record) -> std::io::Result<()> {
        let mut bytes = Vec::new();
        records::encode_record(record, &mut bytes);
        self.append_response_frame(&bytes)
    }
}

impl ResponseSink for Outbox {
    fn append_response_frame(&mut self, record_bytes: &[u8]) -> std::io::Result<()> {
        Outbox::append_response_frame(self, record_bytes)
    }

    fn append_response_record(&mut self, record: &Record) -> std::io::Result<()> {
        Outbox::append_response_record(self, record)
    }
}

struct NullResponseSink;

impl ResponseSink for NullResponseSink {
    fn append_response_frame(&mut self, _record_bytes: &[u8]) -> std::io::Result<()> {
        Ok(())
    }

    fn append_response_record(&mut self, _record: &Record) -> std::io::Result<()> {
        Ok(())
    }
}

fn frame_range(start: usize, end: usize) -> (u32, u32) {
    (
        u32::try_from(start).expect("dedup frame index arena exceeds u32"),
        u32::try_from(end).expect("dedup frame index arena exceeds u32"),
    )
}

struct ArenaResponseSink<'a, S: ResponseSink> {
    inner: &'a mut S,
    byte_arena: &'a mut Vec<u8>,
    frame_arena: &'a mut Vec<FrameSpan>,
}

impl<'a, S: ResponseSink> ArenaResponseSink<'a, S> {
    fn new(
        inner: &'a mut S,
        byte_arena: &'a mut Vec<u8>,
        frame_arena: &'a mut Vec<FrameSpan>,
    ) -> Self {
        Self {
            inner,
            byte_arena,
            frame_arena,
        }
    }
}

impl<S: ResponseSink> ResponseSink for ArenaResponseSink<'_, S> {
    fn append_response_frame(&mut self, record_bytes: &[u8]) -> std::io::Result<()> {
        self.inner.append_response_frame(record_bytes)?;
        let start = u32::try_from(self.byte_arena.len()).expect("dedup byte arena exceeds u32");
        let len = u32::try_from(record_bytes.len()).expect("dedup response frame exceeds u32");
        self.byte_arena.extend_from_slice(record_bytes);
        self.frame_arena.push(FrameSpan { start, len });
        Ok(())
    }

    fn append_response_record(&mut self, record: &Record) -> std::io::Result<()> {
        let start = self.byte_arena.len();
        records::encode_record(record, self.byte_arena);
        let end = self.byte_arena.len();
        self.inner
            .append_response_frame(&self.byte_arena[start..end])?;
        self.frame_arena.push(FrameSpan {
            start: u32::try_from(start).expect("dedup byte arena exceeds u32"),
            len: u32::try_from(end - start).expect("dedup response frame exceeds u32"),
        });
        Ok(())
    }
}

