pub fn encode_log_frame(seq: u64, record: &[u8], out: &mut Vec<u8>) {
    encode_log_frame_record(seq, |out| out.extend_from_slice(record), out);
}

pub fn encode_log_frame_record(
    seq: u64,
    encode_record: impl FnOnce(&mut Vec<u8>),
    out: &mut Vec<u8>,
) {
    let frame_start = out.len();
    write_u32(0, out);
    let seq_offset = out.len();
    write_u64(seq, out);
    let crc_offset = out.len();
    write_u32(0, out);
    let record_offset = out.len();
    encode_record(out);
    let frame_length = out.len() - frame_start - 4;
    out[frame_start..frame_start + 4].copy_from_slice(&(frame_length as u32).to_le_bytes());
    let crc = crc32c_pair(&out[seq_offset..seq_offset + 8], &out[record_offset..]);
    out[crc_offset..crc_offset + 4].copy_from_slice(&crc.to_le_bytes());
}

pub fn validate_log_frame(input: &[u8]) -> Result<(u64, &[u8])> {
    let mut r = Reader::new(input);
    let frame_length = r.u32()? as usize;
    if frame_length != r.remaining() || frame_length < 12 {
        return Err(WireError::BadFrameLength);
    }
    let seq_offset = r.consumed();
    let seq = r.u64()?;
    let stored_crc = r.u32()?;
    let record = r.bytes(frame_length - 12)?;
    let mut crc_input = Vec::with_capacity(8 + record.len());
    crc_input.extend_from_slice(&input[seq_offset..seq_offset + 8]);
    crc_input.extend_from_slice(record);
    let crc = crc32c(&crc_input);
    if crc != stored_crc {
        return Err(WireError::CrcMismatch);
    }
    Ok((seq, record))
}

pub fn write_obox_header(base_seq: u64) -> [u8; 64] {
    let mut header = [0u8; 64];
    header[0..4].copy_from_slice(&OBOX_MAGIC);
    header[4..6].copy_from_slice(&1u16.to_le_bytes());
    header[8..16].copy_from_slice(&base_seq.to_le_bytes());
    let crc = crc32c(&header[0..60]);
    header[60..64].copy_from_slice(&crc.to_le_bytes());
    header
}

pub fn validate_obox_header(header: &[u8]) -> Result<u64> {
    if header.len() != 64 {
        return Err(WireError::ShortRead);
    }
    if header[0..4] != OBOX_MAGIC {
        return Err(WireError::BadMagic);
    }
    let mut r = Reader::new(header);
    r.advance(4)?;
    let format_version = r.u16()?;
    let reserved = r.u16()?;
    let base_seq = r.u64()?;
    let created_at = r.i64()?;
    let reserved_tail = r.bytes(36)?;
    let stored_crc = r.u32()?;
    if format_version != 1
        || reserved != 0
        || created_at != 0
        || reserved_tail.iter().any(|b| *b != 0)
    {
        return Err(WireError::BadReserved);
    }
    if crc32c(&header[0..60]) != stored_crc {
        return Err(WireError::CrcMismatch);
    }
    Ok(base_seq)

