impl Default for Sequencer {
    fn default() -> Self {
        Self::new()
    }
}

pub struct CoreRuntime {
    pub journal_ingress: crate::fanout_ring::JournalConsumer,
    pub matching_ingress: crate::fanout_ring::MatchingConsumer,
    pub durable_cursor: crate::fanout_ring::DurableCursor,
    pub ack_ring: Producer,
    pub input_drained: Arc<AtomicBool>,
    pub writer_done: Arc<AtomicBool>,
    pub run_failed: Arc<AtomicBool>,
    pub outbox: Outbox,
    pub telemetry: Telemetry,
}

pub fn run_core(runtime: CoreRuntime) -> std::io::Result<()> {
    let CoreRuntime {
        journal_ingress,
        matching_ingress,
        durable_cursor,
        mut ack_ring,
        input_drained,
        writer_done,
        run_failed,
        mut outbox,
        mut telemetry,
    } = runtime;
    let (staged_producer, staged_consumer) = staged_channel(STAGED_RING_CAPACITY);
    let matching_done = Arc::new(AtomicBool::new(false));

    let journal_failed = Arc::clone(&run_failed);
    let journal_drained = Arc::clone(&input_drained);
    let journal = thread::spawn(move || {
        let result = journaler_loop(journal_ingress, journal_drained, Arc::clone(&journal_failed));
        if result.is_err() {
            journal_failed.store(true, Ordering::Release);
        }
        result
    });

    let matching_failed = Arc::clone(&run_failed);
    let matching_drained = Arc::clone(&input_drained);
    let matching_done_flag = Arc::clone(&matching_done);
    let matching = thread::spawn(move || {
        let result = matching_loop(
            matching_ingress,
            staged_producer,
            matching_drained,
            Arc::clone(&matching_failed),
        );
        // This means Matching stopped (success, error, or abort), not that it succeeded.
        matching_done_flag.store(true, Ordering::Release);
        if result.is_err() {
            matching_failed.store(true, Ordering::Release);
        }
        result
    });

    let publisher_failed = Arc::clone(&run_failed);
    let publisher_done = Arc::clone(&writer_done);
    let publisher = thread::spawn(move || {
        let result = publisher_loop(
            staged_consumer,
            &mut ack_ring,
            matching_done,
            durable_cursor,
            Arc::clone(&publisher_failed),
            &mut outbox,
            &mut telemetry,
        );
        let final_result = result
            .and_then(|_| outbox.flush())
            .and_then(|_| telemetry.dump());
        publisher_done.store(true, Ordering::Release);
        if final_result.is_err() {
            publisher_failed.store(true, Ordering::Release);
        }
        final_result
    });

    let mut first_error = None;
    for (name, handle) in [
        ("journaler", journal),
        ("matching", matching),
        ("publisher", publisher),
    ] {
        match handle.join() {
            Ok(Ok(())) => {}
            Ok(Err(err)) => {
                run_failed.store(true, Ordering::Release);
                if err.kind() != std::io::ErrorKind::Interrupted && first_error.is_none() {
                    first_error = Some(std::io::Error::new(err.kind(), format!("{name}: {err}")));
                }
            }
            Err(_) => {
                run_failed.store(true, Ordering::Release);
                if first_error.is_none() {
                    first_error = Some(std::io::Error::other(format!("{name} thread panicked")));
                }
            }
        }
    }

    if let Some(err) = first_error {
        Err(err)
    } else {
        Ok(())
    }
}

fn journaler_loop(
    mut ingress: crate::fanout_ring::JournalConsumer,
    input_drained: Arc<AtomicBool>,
    run_failed: Arc<AtomicBool>,
) -> std::io::Result<()> {
    let mut staged_bytes = Vec::new();
    loop {
        if run_failed.load(Ordering::Acquire) {
            return Ok(());
        }
        match ingress.try_pop() {
            Ok(item) => {
                // Phase 1's durable cursor is this journal cursor: memory-stage the raw bytes and
                // advance immediately. Phase 2 attaches append/fsync/hash-chain work here.
                staged_bytes.clear();
                staged_bytes.extend_from_slice(item.bytes());
                std::hint::black_box(staged_bytes.len());
                drop(item);
                continue;
            }
            Err(RingError::Empty) => {}
            Err(err) => {
                return Err(std::io::Error::other(format!(
                    "journal ring pop failed: {err:?}"
                )));
            }
        }
        if raw_journal_drained_after_flag(&ingress, &input_drained) {
            return Ok(());
        }
        thread::sleep(Duration::from_micros(50));
    }
}

fn matching_loop(
    mut ingress: crate::fanout_ring::MatchingConsumer,
    mut staged: StagedProducer,
    input_drained: Arc<AtomicBool>,
    run_failed: Arc<AtomicBool>,
) -> std::io::Result<()> {
    let mut sequencer = Sequencer::new();
    loop {
        if run_failed.load(Ordering::Acquire) {
            return Ok(());
        }
        match ingress.try_pop() {
            Ok(item) => {
                let ingress_ns = item.ingress_ns();
                let index = item.index();
                let mut slot = staged.reserve_abortable(&run_failed)?;
                let ack = {
                    let mut sink = slot.sink();
                    sequencer.accept_with_sink(item.bytes(), &mut sink)?
                };
                slot.commit(index, ingress_ns, ack);
                drop(item);
                continue;
            }
            Err(RingError::Empty) => {}
            Err(err) => {
                return Err(std::io::Error::other(format!(
                    "matching ring pop failed: {err:?}"
                )));
            }
        }
        if raw_matching_drained_after_flag(&ingress, &input_drained) {
            return Ok(());
        }
        thread::sleep(Duration::from_micros(50));
    }
}

fn publisher_loop(
    mut staged: StagedConsumer,
    ack_ring: &mut Producer,
    matching_done: Arc<AtomicBool>,
    durable_cursor: crate::fanout_ring::DurableCursor,
    run_failed: Arc<AtomicBool>,
    outbox: &mut Outbox,
    telemetry: &mut Telemetry,
) -> std::io::Result<()> {
    let mut ack_scratch = Vec::new();
    loop {
        match staged.try_pop() {
            Ok(item) => {
                while item.input_index() >= durable_cursor.next_index() {
                    if run_failed.load(Ordering::Acquire) {
                        return Ok(());
                    }
                    thread::sleep(Duration::from_micros(50));
                }
                for frame in item.frames() {
                    outbox.append_response_frame(frame)?;
                }
                let ack = item.ack().clone();
                if ack.disposition == AckKind::Sequenced {
                    telemetry.record_seq(ack.seq, item.ingress_ns(), now_mono_ns());
                }
                encode_ack_record_into(&ack, &mut ack_scratch);
                push_ack_abortable(ack_ring, &ack_scratch, &run_failed)?;
                item.publish_done();
                continue;
            }
            Err(RingError::Empty) => {}
            Err(err) => {
                return Err(std::io::Error::other(format!(
                    "staged ring pop failed: {err:?}"
                )));
            }
        }
        if run_failed.load(Ordering::Acquire) || staged_drained_after_flag(&staged, &matching_done) {
            return Ok(());
        }
        thread::sleep(Duration::from_micros(50));
    }
}

