//! Single-producer/two-consumer fixed-slot fan-out ring for raw ingress bytes.
//!
//! Slots are read-only after the producer commits them. The producer may reuse a slot only after
//! both consumers have advanced past it.
//!
//! A consumed item's bytes are only accessible through methods that borrow the guard, so the slice
//! cannot outlive the guard that holds that consumer cursor.
//!
//! ```compile_fail
//! use spine::fanout_ring::channel;
//!
//! let (mut producer, mut journal, _matching) = channel(1);
//! let mut slot = producer.try_reserve(3).unwrap();
//! slot.bytes_mut().copy_from_slice(b"one");
//! slot.commit(1);
//! let item = journal.try_pop().unwrap();
//! let leaked = item.bytes();
//! drop(item);
//! assert_eq!(leaked, b"one");
//! ```

use std::cell::{Cell, UnsafeCell};
use std::fmt;
use std::marker::PhantomData;
use std::ops::Deref;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::thread;

use crate::ring::{RingError, SLOT_CAP};

struct Slot {
    len: usize,
    ingress_ns: u64,
    bytes: [u8; SLOT_CAP],
}

impl Slot {
    fn empty() -> Self {
        Self {
            len: 0,
            ingress_ns: 0,
            bytes: [0; SLOT_CAP],
        }
    }
}

struct Inner {
    slots: Box<[UnsafeCell<Slot>]>,
    mask: usize,
    tail: AtomicUsize,
    journal_cursor: AtomicUsize,
    matching_cursor: AtomicUsize,
}

unsafe impl Send for Inner {}
unsafe impl Sync for Inner {}

pub struct Producer {
    inner: Arc<Inner>,
    _not_sync: PhantomData<Cell<()>>,
}

pub struct JournalConsumer {
    inner: Arc<Inner>,
    _not_sync: PhantomData<Cell<()>>,
}

pub struct MatchingConsumer {
    inner: Arc<Inner>,
    _not_sync: PhantomData<Cell<()>>,
}

#[derive(Clone)]
pub struct DurableCursor {
    inner: Arc<Inner>,
}

pub struct ReservedSlot<'a> {
    inner: &'a Inner,
    slot: &'a mut Slot,
    tail: usize,
    len: usize,
    committed: bool,
}

pub struct RawItem<'a> {
    cursor: &'a AtomicUsize,
    index: usize,
    bytes: &'a [u8],
    ingress_ns: u64,
}

pub fn channel(capacity: usize) -> (Producer, JournalConsumer, MatchingConsumer) {
    assert!(capacity.is_power_of_two());
    assert!(capacity > 0);
    let slots = (0..capacity)
        .map(|_| UnsafeCell::new(Slot::empty()))
        .collect::<Vec<_>>()
        .into_boxed_slice();
    let inner = Arc::new(Inner {
        slots,
        mask: capacity - 1,
        tail: AtomicUsize::new(0),
        journal_cursor: AtomicUsize::new(0),
        matching_cursor: AtomicUsize::new(0),
    });
    (
        Producer {
            inner: Arc::clone(&inner),
            _not_sync: PhantomData,
        },
        JournalConsumer {
            inner: Arc::clone(&inner),
            _not_sync: PhantomData,
        },
        MatchingConsumer {
            inner,
            _not_sync: PhantomData,
        },
    )
}

impl Producer {
    pub fn try_reserve(&mut self, len: usize) -> Result<ReservedSlot<'_>, RingError> {
        try_reserve_inner(&self.inner, len)
    }

    pub fn reserve(&mut self, len: usize) -> Result<ReservedSlot<'_>, RingError> {
        let inner = &*self.inner;
        loop {
            match try_reserve_inner(inner, len) {
                Err(RingError::Full) => thread::yield_now(),
                other => return other,
            }
        }
    }

    pub fn tail(&self) -> usize {
        self.inner.tail.load(Ordering::Acquire)
    }
}

fn try_reserve_inner(inner: &Inner, len: usize) -> Result<ReservedSlot<'_>, RingError> {
    if len > SLOT_CAP {
        return Err(RingError::TooLarge { len, cap: SLOT_CAP });
    }
    let tail = inner.tail.load(Ordering::Relaxed);
    let journal = inner.journal_cursor.load(Ordering::Acquire);
    let matching = inner.matching_cursor.load(Ordering::Acquire);
    let retired = journal.min(matching);
    if tail.wrapping_sub(retired) == inner.slots.len() {
        return Err(RingError::Full);
    }
    let idx = tail & inner.mask;
    let slot = unsafe { &mut *inner.slots[idx].get() };
    Ok(ReservedSlot {
        inner,
        slot,
        tail,
        len,
        committed: false,
    })
}

impl ReservedSlot<'_> {
    pub fn bytes_mut(&mut self) -> &mut [u8] {
        &mut self.slot.bytes[..self.len]
    }

    pub fn commit(mut self, ingress_ns: u64) {
        self.slot.len = self.len;
        self.slot.ingress_ns = ingress_ns;
        self.inner
            .tail
            .store(self.tail.wrapping_add(1), Ordering::Release);
        self.committed = true;
    }
}

impl Drop for ReservedSlot<'_> {
    fn drop(&mut self) {
        if !self.committed {
            self.slot.len = 0;
            self.slot.ingress_ns = 0;
        }
    }
}

impl JournalConsumer {
    pub fn try_pop(&mut self) -> Result<RawItem<'_>, RingError> {
        try_pop_inner(&self.inner, &self.inner.journal_cursor)
    }

    pub fn durable_cursor(&self) -> DurableCursor {
        DurableCursor {
            inner: Arc::clone(&self.inner),
        }
    }

    pub fn cursor(&self) -> usize {
        self.inner.journal_cursor.load(Ordering::Acquire)
    }

    pub fn tail(&self) -> usize {
        self.inner.tail.load(Ordering::Acquire)
    }
}

impl MatchingConsumer {
    pub fn try_pop(&mut self) -> Result<RawItem<'_>, RingError> {
        try_pop_inner(&self.inner, &self.inner.matching_cursor)
    }

    pub fn cursor(&self) -> usize {
        self.inner.matching_cursor.load(Ordering::Acquire)
    }

    pub fn tail(&self) -> usize {
        self.inner.tail.load(Ordering::Acquire)
    }
}

fn try_pop_inner<'a>(
    inner: &'a Inner,
    cursor: &'a AtomicUsize,
) -> Result<RawItem<'a>, RingError> {
    let index = cursor.load(Ordering::Relaxed);
    let tail = inner.tail.load(Ordering::Acquire);
    if index == tail {
        return Err(RingError::Empty);
    }
    let idx = index & inner.mask;
    let slot = unsafe { &*inner.slots[idx].get() };
    Ok(RawItem {
        cursor,
        index,
        bytes: &slot.bytes[..slot.len],
        ingress_ns: slot.ingress_ns,
    })
}

impl RawItem<'_> {
    pub fn index(&self) -> usize {
        self.index
    }

    pub fn ingress_ns(&self) -> u64 {
        self.ingress_ns
    }

    pub fn bytes(&self) -> &[u8] {
        self.bytes
    }
}

impl Deref for RawItem<'_> {
    type Target = [u8];

    fn deref(&self) -> &Self::Target {
        self.bytes()
    }
}

impl Drop for RawItem<'_> {
    fn drop(&mut self) {
        self.cursor
            .store(self.index.wrapping_add(1), Ordering::Release);
    }
}

impl fmt::Debug for RawItem<'_> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("RawItem")
            .field("index", &self.index)
            .field("len", &self.bytes.len())
            .field("ingress_ns", &self.ingress_ns)
            .finish()
    }
}

impl DurableCursor {
    pub fn next_index(&self) -> usize {
        self.inner.journal_cursor.load(Ordering::Acquire)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn raw_slot_retires_only_after_both_consumers_advance() {
        let (mut producer, mut journal, mut matching) = channel(1);
        {
            let mut slot = producer.try_reserve(3).unwrap();
            slot.bytes_mut().copy_from_slice(b"one");
            slot.commit(1);
        }
        let journal_item = journal.try_pop().unwrap();
        assert_eq!(journal_item.bytes(), b"one");
        drop(journal_item);
        assert!(matches!(producer.try_reserve(3), Err(RingError::Full)));
        let matching_item = matching.try_pop().unwrap();
        assert_eq!(matching_item.bytes(), b"one");
        drop(matching_item);
        let mut slot = producer.try_reserve(3).unwrap();
        slot.bytes_mut().copy_from_slice(b"two");
        slot.commit(2);
    }

    #[test]
    fn consumers_track_absolute_next_index_cursors() {
        let (mut producer, mut journal, mut matching) = channel(2);
        for (idx, byte) in [b'a', b'b', b'c', b'd'].into_iter().enumerate() {
            while producer.try_reserve(1).is_err() {
                drop(journal.try_pop().unwrap());
                drop(matching.try_pop().unwrap());
            }
            let mut slot = producer.try_reserve(1).unwrap();
            slot.bytes_mut()[0] = byte;
            slot.commit(idx as u64);
        }
        while journal.cursor() < producer.tail() {
            drop(journal.try_pop().unwrap());
        }
        while matching.cursor() < producer.tail() {
            drop(matching.try_pop().unwrap());
        }
        assert_eq!(journal.cursor(), 4);
        assert_eq!(matching.cursor(), 4);
    }
}

